code.snippet:
// ❌ BAD - developer uses class for a coordinate and gets accidental sharing
class Coordinate { public double Lat; public double Lng; }
Coordinate origin = new Coordinate { Lat = 51.5, Lng = -0.1 };
Coordinate waypoint = origin;
waypoint.Lat = 48.8; // intended to move only waypoint
Console.WriteLine(origin.Lat); // 48.8 - origin was also moved

// ✅ GOOD - use struct for small data with value semantics
struct Coordinate { public double Lat; public double Lng; }
Coordinate origin = new Coordinate { Lat = 51.5, Lng = -0.1 };
Coordinate waypoint = origin;
waypoint.Lat = 48.8;
Console.WriteLine(origin.Lat); // 51.5 - origin unchanged

