code.snippet:
// ❌ BAD - expecting struct mutation to reach the caller
struct PageViewCounter { public int Count; }
void TrackView(PageViewCounter c) { c.Count++; } // mutates local copy only
PageViewCounter pvc = new PageViewCounter { Count = 0 };
TrackView(pvc);
Console.WriteLine(pvc.Count); // 0 - bug: view was not tracked

// ✅ GOOD - use ref to modify the caller's struct
void TrackView(ref PageViewCounter c) { c.Count++; }
TrackView(ref pvc);
Console.WriteLine(pvc.Count); // 1

