code.snippet:
// ❌ BAD - developer confuses List and array behavior and writes wrong code
var points = new List<Point> { new Point { X = 1 } };
points[0].X = 99; // CS1612 compile error

// ✅ GOOD - arrays allow direct in-place mutation of struct elements
Point[] arr = { new Point { X = 1 } };
arr[0].X = 99; // compiles and works - direct lvalue access
